#include <stdio.h>
#include <stdlib.h>

int max(int a, int b) {
    return (a > b) ? a : b;
}

int longest_increasing_subsequence(int* arr, int n, int li, int ri) {
    int** dp = (int**)malloc((ri - li + 1) * sizeof(int*));
    for (int i = 0; i <= ri - li; i++) {
        dp[i] = (int*)malloc((ri - li + 1) * sizeof(int));
    }
    for (int i = 0; i <= ri - li; i++) {
        for (int j = 0; j <= ri - li; j++) {
            if (i == j) {
                dp[i][j] = 1;
            } else if (arr[i + li] < arr[j + li]) {
                dp[i][j] = max(dp[i][j - 1], dp[i][j - 1] + 1);
            } else {
                dp[i][j] = dp[i][j - 1];
            }
        }
    }
    int result = dp[0][ri - li];
    for (int i = 0; i <= ri - li; i++) {
        free(dp[i]);
    }
    free(dp);
    return result;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int* arr = (int*)malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &arr[i]);
        }
        for (int i = 0; i < m; i++) {
            int li, ri;
            scanf("%d %d", &li, &ri);
            li--;
            ri--;
            printf("%d\n", longest_increasing_subsequence(arr, n, li, ri));
        }
        free(arr);
    }
    return 0;
}

