import java.util.Scanner;
public class Main {
    public static int max(int a, int b) {
        return (a > b) ? a : b;
    }
    public static int longest_increasing_subsequence(int[] arr, int n, int li, int ri) {
        int[][] dp = new int[ri - li + 1][ri - li + 1];
        for (int i = 0; i <= ri - li; i++) {
            for (int j = 0; j <= ri - li; j++) {
                if (i == j) {
                    dp[i][j] = 1;
                } else if (arr[i + li] < arr[j + li]) {
                    dp[i][j] = max(dp[i][j - 1], dp[i][j - 1] + 1);
                } else {
                    dp[i][j] = dp[i][j - 1];
                }
            }
        }
        return dp[0][ri - li];
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();
        while (t-- > 0) {
            int n = scanner.nextInt();
            int m = scanner.nextInt();
            int[] arr = new int[n];
            for (int i = 0; i < n; i++) {
                arr[i] = scanner.nextInt();
            }
            for (int i = 0; i < m; i++) {
                int li = scanner.nextInt();
                int ri = scanner.nextInt();
